  LESSON_QUESTIONS['Persuasion']['Door in Face'] = [
    { type: 'multiple_choice', prompt: 'What is the "door-in-the-face" technique?', options: ['Slamming a door in someone\'s face', 'Making a large request first (which will be refused), then following with a smaller, actual request', 'Opening a door for someone politely', 'Knocking on doors for charity'], correctAnswer: 'Making a large request first (which will be refused), then following with a smaller, actual request', difficulty: 'easy', explanation: 'The rejected large request makes the subsequent smaller request seem very reasonable by contrast.' },
    { type: 'true_false', prompt: 'The door-in-the-face technique leverages the contrast principle and reciprocal concessions.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'The contrast makes the second request seem small, and the "concession" triggers reciprocity.' },
    { type: 'multiple_choice', prompt: 'A fundraiser asks for $500 (refused), then asks for $25. The $25 seems:', options: ['Still too expensive', 'Very reasonable compared to $500', 'Exactly the same', 'More expensive than $500'], correctAnswer: 'Very reasonable compared to $500', difficulty: 'easy', explanation: 'The anchoring from $500 makes $25 feel trivial — a classic contrast effect.' },
    { type: 'fill_gap', prompt: 'For door-in-the-face to work, both requests should come from the ___ person or organization.', options: ['Same', 'Different', 'Unknown', 'Famous'], correctAnswer: 'Same', difficulty: 'medium', explanation: 'The concession dynamic only works when the same requester "retreats" from their original ask.' },
    { type: 'true_false', prompt: 'The initial large request should be extreme but not absurd, otherwise credibility is lost.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'If the first request is laughably unreasonable, the technique backfires — it must be plausible enough to seem genuine.' },
    { type: 'multiple_choice', prompt: 'How does door-in-the-face differ from foot-in-the-door?', options: ['They are the same technique', 'Door-in-the-face starts large then goes small; foot-in-the-door starts small then goes large', 'Foot-in-the-door starts large', 'Door-in-the-face only works online'], correctAnswer: 'Door-in-the-face starts large then goes small; foot-in-the-door starts small then goes large', difficulty: 'easy', explanation: 'They work in opposite directions: DITF uses contrast and reciprocity; FITD uses consistency and commitment.' },
    { type: 'true_false', prompt: 'The door-in-the-face technique works best when requests are made close together in time.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'hard', explanation: 'The reciprocity feeling fades with time; both requests should be close together for maximum effect.' },
    { type: 'multiple_choice', prompt: 'Real estate agents often show overpriced houses first, then the target property. This uses:', options: ['Social proof', 'The door-in-the-face / contrast principle', 'Authority', 'Liking'], correctAnswer: 'The door-in-the-face / contrast principle', difficulty: 'medium', explanation: 'The expensive house makes the target property seem like a bargain — pure contrast effect.' },
  ];

  LESSON_QUESTIONS['Persuasion']['Contrast Principle'] = [
    { type: 'multiple_choice', prompt: 'The contrast principle states that:', options: ['Everything should be compared to its own merits', 'We judge things differently based on what we experienced immediately before', 'Contrasting colors are more appealing', 'Contrast reduces persuasion'], correctAnswer: 'We judge things differently based on what we experienced immediately before', difficulty: 'easy', explanation: 'Sequential exposure changes perception — a warm room feels hot after being in a cold one.' },
    { type: 'true_false', prompt: 'A $50 accessory seems cheap after you just bought a $2,000 suit.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Contrast with the expensive suit makes the accessory seem insignificant — a proven retail strategy.' },
    { type: 'multiple_choice', prompt: 'Salespeople use the contrast principle by:', options: ['Showing the cheapest item first', 'Showing the most expensive item first, making subsequent items seem affordable', 'Showing all items at once', 'Hiding all prices'], correctAnswer: 'Showing the most expensive item first, making subsequent items seem affordable', difficulty: 'medium', explanation: 'The expensive reference point makes all subsequent items feel like good deals by comparison.' },
    { type: 'fill_gap', prompt: 'The contrast principle is a form of perceptual ___ — our senses compare rather than measure absolutely.', options: ['Bias', 'Strength', 'Training', 'Memory'], correctAnswer: 'Bias', difficulty: 'medium', explanation: 'Our brains process differences relative to context, not absolute values — this is fundamental to how perception works.' },
    { type: 'true_false', prompt: 'Listing a high "original price" next to a discounted price uses the contrast principle.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'The original price creates a reference that makes the discount look much more attractive.' },
    { type: 'multiple_choice', prompt: 'In job interviews, the contrast principle means:', options: ['All candidates are judged equally', 'A mediocre candidate seems better after several weak ones', 'The first candidate always gets the job', 'Only the last candidate matters'], correctAnswer: 'A mediocre candidate seems better after several weak ones', difficulty: 'medium', explanation: 'Interview order affects evaluation — a decent candidate after poor ones benefits from the contrast.' },
    { type: 'true_false', prompt: 'The contrast principle only affects visual perception, not judgments about price or quality.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Contrast affects all judgments — price, quality, beauty, difficulty, and more.' },
    { type: 'multiple_choice', prompt: 'To defend against the contrast principle, you should:', options: ['Never compare anything', 'Evaluate each option on its own merits, not just relative to what came before', 'Always choose the cheapest option', 'Choose the first thing you see'], correctAnswer: 'Evaluate each option on its own merits, not just relative to what came before', difficulty: 'easy', explanation: 'Absolute evaluation based on your needs and research neutralizes contrast manipulation.' },
  ];

